hooks.command:
set -euo pipefail; payload=$(cat); repo=$(printf '%s' "$payload" | jq -r '.repoPath // .repository // .cwd // .project_path // .workspacePath // .tool_input.repoPath // .tool_input.cwd // empty'); [ -n "$repo" ] || repo="$PWD"; path=$(printf '%s' "$payload" | jq -r '.worktreePath // .path // .tool_input.worktreePath // .tool_input.path // empty'); if [ -z "$path" ]; then printf '{"continue":false,"stopReason":"WorktreeRemove: path ausente no payload"}
'; exit 0; fi; git -C "$repo" worktree remove "$path" --force; printf '{"systemMessage":"Worktree removido: %s"}
' "$path"
